 1→export const STAR_COLORS = ['#5f92ff', '#ff5fa2', '#5fffb0', '#ffd75f', '#b05fff', '#ff8a5f'];
 2→
 3→export const HOME_SCALE = 0.8;
 4→export const GUEST_SCALE = 0.05;
 5→
 6→export const simpleHash = (str) => {
 7→    let h = 0;
 8→    for (let i = 0; i < str.length; i++) {
 9→        h = ((h << 5) - h + str.charCodeAt(i)) | 0;
10→    }
11→    return Math.abs(h);
12→};
13→
14→export const userHomeCoords = (userId) => {
15→    if (!userId) return { x: 0, y: 0 };
16→    const mid = Math.floor(userId.length / 2);
17→    const xHash = simpleHash(userId.slice(0, mid));
18→    const yHash = simpleHash(userId.slice(mid));
19→    const x = (xHash % 50001) / 50000 * 50000 - 25000;
20→    const y = (yHash % 50001) / 50000 * 50000 - 25000;
21→    return { x, y };
22→};
23→
24→export const getStarColor = (userId) => {
25→    if (!userId) return STAR_COLORS[0];
26→    return STAR_COLORS[simpleHash(userId) % STAR_COLORS.length];
27→};
28→
29→export const getStarRadius = (likeCount) => {
30→    const likes = Math.min(likeCount || 0, 20);
31→    return 6 + likes * 0.3;
32→};
33→
34→export const extractSnippet = (post) => {
35→    if (post.post_type === 'canvas' && post.canvas_doc?.snippets) {
36→        return post.canvas_doc.snippets
37→            .map(s => s?.text || '')
38→            .filter(Boolean)
39→            .join(' ')
40→            .slice(0, 200);
41→    }
42→    if (typeof post.content === 'string') {
43→        try {
44→            const parsed = JSON.parse(post.content);
45→            const extractText = (node) => {
46→                if (!node) return '';
47→                if (typeof node.text === 'string') return node.text;
48→                if (Array.isArray(node.children)) {
49→                    return node.children.map(extractText).join('');
50→                }
51→                return '';
52→            };
53→            return extractText(parsed.root || parsed).slice(0, 200);
54→        } catch {
55→            return post.content.slice(0, 200);
56→        }
57→    }
58→    return '';
59→};
